+
+    #[test]
+    fn one_lever_protocol_accepts_exactly_one_change() {
+        let baseline = LeverSnapshot::from_pairs([
+            ("query.semantic_fanout", "64"),
+            ("crawl.batch_size", "200"),
+        ]);
